// An object from a library you don't control
const libraryObject = {
  id: 'USER_123',
  name: 'Alice'
};

// You want to add your own ID, but you don't want to break their 'id'.
const myCustomId = Symbol('id');

libraryObject[myCustomId] = 9999;

console.log(libraryObject.id); // 'USER_123' (Theirs is safe!)
console.log(libraryObject[myCustomId]); // 9999 (Yours works!)

// Symbols are hidden from normal loops
console.log(Object.keys(libraryObject)); // ['id', 'name']
